if (!Array.isArray(msg.payload)) {
    node.error("payload is NOT array", msg.payload);
    return null;
}

function deepClean(obj) {
    return JSON.parse(JSON.stringify(obj));
}

/* Protected of Mongodb Error($, .) */
function sanitizeKeys(obj) {
    if (Array.isArray(obj)) {
        return obj.map(sanitizeKeys);
    }

    if (obj && typeof obj === "object") {
        const clean = {};
        for (const [k, v] of Object.entries(obj)) {
            if (k.startsWith("$") || k.includes(".")) continue;
            clean[k] = sanitizeKeys(v);
        }
        return clean;
    }
    return obj;
}

const BATCH_SIZE = 200;
const ops = [];

for (const item of msg.payload) {
    const mac = item?.mac || item?._attr?.mac;
    if (!mac) continue;

    const rawData = item.data ?? item;
    const safeData = sanitizeKeys(deepClean(rawData));

    ops.push({
        updateOne: {
            filter: { mac },
            update: {
                $set: {
                    mac,
                    ...safeData
                },
                $currentDate: { lastModified: true },
            },
            upsert: true,
        }
    })
}

if (ops.length === 0) return null;

/* แยก batch -> 1 msg = 1 bulkWrite */
const messages = [];
for (let i = 0; i < ops.length; i += BATCH_SIZE) {
    messages.push({
        collection: "alarms_aggregate",
        operation: "bulkWrite",
        payload: ops.slice(i, i + BATCH_SIZE),
        options: { ordered: false }
    })
}
const now = new Date();
node.status({
    fill: "green",
    shape: "dot",
    text: `BulkWrite ${messages.length} batch(es) @ ${now.toLocaleString("en-GB", {
        timeZone: "Asia/Bangkok",
        hour12: false
    })}`
});

return [messages];

const BATCH_SIZE = 100;
const item = msg.payload || {};

function stat(name, n = 1) {
    const s = flow.get("agg_only_stats") || {};
    s[name] = (s[name] || 0) + n;
    s.lastMsgAt = Date.now();
    flow.set("agg_only_stats", s);
}

let dataAllBuffer = flow.get("agg_only_data_all_buffer") || [];
let alarmBuffer = flow.get("agg_only_alarm_buffer") || [];

if (item.dataAll) {
    dataAllBuffer.push(item.dataAll);
    stat("dataAllOps");
}

if (item.alarmAggregate) {
    alarmBuffer.push(item.alarmAggregate);
    stat("alarmOps");
}

const messages = [];

if (dataAllBuffer.length >= BATCH_SIZE) {
    messages.push({
        collection: "data_all",
        operation: "bulkWrite",
        payload: dataAllBuffer.splice(0, BATCH_SIZE),
        options: { ordered: false },
        topic: "bulkWrite:data_all"
    });
    stat("dataAllBatches");
}

if (alarmBuffer.length >= BATCH_SIZE) {
    messages.push({
        collection: "alarms_aggregate",
        operation: "bulkWrite",
        payload: alarmBuffer.splice(0, BATCH_SIZE),
        options: { ordered: false },
        topic: "bulkWrite:alarms_aggregate"
    });
    stat("alarmBatches");
}

flow.set("agg_only_data_all_buffer", dataAllBuffer);
flow.set("agg_only_alarm_buffer", alarmBuffer);

// ส่งออกหลาย msg ใน output เดียว
if (messages.length > 0) {
    return [messages];
}

return null;
